{
  "query": "fragment TopicFields on Topic {
    id
    name
    slug
    description
    postsCount
    followersCount
    isFollowing
    createdAt
    url
    image
  }
query Topic($id: ID, $slug: String) { topic(id: $id, slug: $slug) { ...TopicFields } }",
  "variables": {
    "slug": "{{sample_topic_slug}}"
  }
}

{
  "query": "fragment PageInfoFields on PageInfo {
    hasNextPage
    hasPreviousPage
    startCursor
    endCursor
  }
fragment TopicFields on Topic {
    id
    name
    slug
    description
    postsCount
    followersCount
    isFollowing
    createdAt
    url
    image
  }
query Topics( $followedByUserid: ID $query: String $order: TopicsOrder $after: String $before: String $first: Int $last: Int ) { topics( followedByUserid: $followedByUserid query: $query order: $order after: $after before: $before first: $first last: $last ) { edges { cursor node { ...TopicFields } } nodes { ...TopicFields } pageInfo { ...PageInfoFields } totalCount } }",
  "variables": {
    "first": 10,
    "order": "FOLLOWERS_COUNT",
    "query": "ai"
  }
}

{
  "query": "\nquery Viewer { viewer { user { id name username url } } }"
}

{
  "query": "fragment UserCoreFields on User {
    id
    name
    username
    headline
    url
    websiteUrl
    twitterUsername
    followersCount
    followingCount
    isFollowing
    isMaker
    isViewer
    createdAt
    profileImage
    coverImage
  }
mutation UserFollow($input: UserFollowInput!) { userFollow(input: $input) { clientMutationId errors { field message } node { ...UserCoreFields } } }",
  "variables": {
    "input": {
      "userId": "{{sample_user_id}}"
    }
  }
}

{
  "query": "fragment UserCoreFields on User {
